package com.enterprise.auth.service;

import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.BackupCodeRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {

    private static final Logger logger = LoggerFactory.getLogger(BackupCodeService.class);
    private static final int BACKUP_CODE_COUNT = 10;
    private static final int BACKUP_CODE_LENGTH = 8;
    private static final String BACKUP_CODE_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom;

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
        this.secureRandom = new SecureRandom();
    }

    @Transactional
    public List<String> generateBackupCodes(User user) {
        logger.info("Generating backup codes for user: {}", user.getUsername());

        // Remove existing backup codes
        backupCodeRepository.deleteAllByUser(user);

        List<String> plainTextCodes = new ArrayList<>();

        for (int i = 0; i < BACKUP_CODE_COUNT; i++) {
            String code = generateRandomCode();
            plainTextCodes.add(formatCode(code));

            BackupCode backupCode = new BackupCode();
            backupCode.setCodeHash(passwordEncoder.encode(code.toUpperCase()));
            backupCode.setUsed(false);
            backupCode.setUser(user);

            backupCodeRepository.save(backupCode);
        }

        logger.info("Generated {} backup codes for user: {}", BACKUP_CODE_COUNT, user.getUsername());
        return plainTextCodes;
    }

    @Transactional
    public boolean verifyBackupCode(User user, String providedCode) {
        String normalizedCode = providedCode.replaceAll("[\\s-]", "").toUpperCase();

        List<BackupCode> unusedCodes = backupCodeRepository.findByUserAndUsedFalse(user);

        for (BackupCode backupCode : unusedCodes) {
            if (passwordEncoder.matches(normalizedCode, backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(LocalDateTime.now());
                backupCodeRepository.save(backupCode);

                long remaining = backupCodeRepository.countByUserAndUsedFalse(user);
                logger.info("Backup code used for user: {}. Remaining codes: {}", user.getUsername(), remaining);

                if (remaining <= 2) {
                    logger.warn("User {} has only {} backup codes remaining!", user.getUsername(), remaining);
                }

                return true;
            }
        }

        logger.warn("Invalid backup code attempt for user: {}", user.getUsername());
        return false;
    }

    public long getRemainingCodesCount(User user) {
        return backupCodeRepository.countByUserAndUsedFalse(user);
    }

    @Transactional
    public List<String> regenerateBackupCodes(User user) {
        logger.info("Regenerating backup codes for user: {}", user.getUsername());
        return generateBackupCodes(user);
    }

    private String generateRandomCode() {
        StringBuilder code = new StringBuilder();
        for (int i = 0; i < BACKUP_CODE_LENGTH; i++) {
            int index = secureRandom.nextInt(BACKUP_CODE_CHARS.length());
            code.append(BACKUP_CODE_CHARS.charAt(index));
        }
        return code.toString();
    }

    private String formatCode(String code) {
        // Format as XXXX-XXXX for readability
        if (code.length() == 8) {
            return code.substring(0, 4) + "-" + code.substring(4);
        }
        return code;
    }
}

// === Service: TotpService ===

package com.enterprise.auth.service;

import org.springframework.stereotype.Service;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.ByteBuffer;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;

@Service
public class TotpService {

    private static final int SECRET_LENGTH = 20;
    private static final int CODE_DIGITS = 6;
    private static final int TIME_STEP = 30;
    private static final int WINDOW = 1;
    private static final String ALGORITHM = "HmacSHA1";

    private final SecureRandom secureRandom = new SecureRandom();

    public String generateSecret() {
        byte[] secretBytes = new byte[SECRET_LENGTH];
        secureRandom.nextBytes(secretBytes);
        return base32Encode(secretBytes);
    }

    public boolean verifyCode(String secret, String code) {
        try {
            int codeInt = Integer.parseInt(code);
            long currentTime = Instant.now().getEpochSecond() / TIME_STEP;

            for (int i = -WINDOW; i <= WINDOW; i++) {
                int generatedCode = generateCode(secret, currentTime + i);
                if (generatedCode == codeInt) {
                    return true;
                }
            }
        } catch (NumberFormatException e) {
            return false;
        } catch (Exception e) {
            return false;
        }
        return false;
    }

    public String generateQrCodeUri(String secret, String username, String issuer) {
        return String.format("otpauth://totp/%s:%s?secret=%s&issuer=%s&algorithm=SHA1&digits=%d&period=%d",
                issuer, username, secret, issuer, CODE_DIGITS, TIME_STEP);
    }

    private int generateCode(String secret, long timeCounter) throws Exception {
        byte[] secretBytes = base32Decode(secret);
        byte[] timeBytes = ByteBuffer.allocate(8).putLong(timeCounter).array();

        Mac mac = Mac.getInstance(ALGORITHM);
        mac.init(new SecretKeySpec(secretBytes, ALGORITHM));
        byte[] hash = mac.doFinal(timeBytes);

        int offset = hash[hash.length - 1] & 0x0F;
        int binary = ((hash[offset] & 0x7F) << 24)
                | ((hash[offset + 1] & 0xFF) << 16)
                | ((hash[offset + 2] & 0xFF) << 8)
                | (hash[offset + 3] & 0xFF);

        return binary % (int) Math.pow(10, CODE_DIGITS);
    }

    private String base32Encode(byte[] data) {
        String base32Chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
        StringBuilder result = new StringBuilder();
        int buffer = 0;
        int bitsLeft = 0;

        for (byte b : data) {
            buffer = (buffer << 8) | (b & 0xFF);
            bitsLeft += 8;
            while (bitsLeft >= 5) {
                bitsLeft -= 5;
                result.append(base32Chars.charAt((buffer >> bitsLeft) & 0x1F));
            }
        }

        if (bitsLeft > 0) {
            result.append(base32Chars.charAt((buffer << (5 - bitsLeft)) & 0x1F));
        }

        return result.toString();
    }

    private byte[] base32Decode(String encoded) {
        String base32Chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
        encoded = encoded.toUpperCase().replaceAll("[^A-Z2-7]", "");

        int buffer = 0;
        int bitsLeft = 0;
        java.io.ByteArrayOutputStream output = new java.io.ByteArrayOutputStream();

        for (char c : encoded.toCharArray()) {
            int val = base32Chars.indexOf(c);
            if (val < 0) continue;
            buffer = (buffer << 5) | val;
            bitsLeft += 5;
            if (bitsLeft >= 8) {
                bitsLeft -= 8;
                output.write((buffer >> bitsLeft) & 0xFF);
            }
        }

        return output.toByteArray();
    }
}

