package com.enterprise.auth.service;

import com.enterprise.auth.entity.MfaAuditLog;
import com.enterprise.auth.repository.MfaAuditLogRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;

@Service
public class AuditService {

    private static final Logger logger = LoggerFactory.getLogger(AuditService.class);
    private static final int MAX_FAILED_ATTEMPTS = 5;
    private static final int LOCKOUT_MINUTES = 15;

    private final MfaAuditLogRepository auditLogRepository;

    public AuditService(MfaAuditLogRepository auditLogRepository) {
        this.auditLogRepository = auditLogRepository;
    }

    public void logEvent(Long userId, String action, boolean success, String ipAddress, String userAgent, String details) {
        MfaAuditLog log = new MfaAuditLog();
        log.setUserId(userId);
        log.setAction(action);
        log.setSuccess(success);
        log.setIpAddress(ipAddress);
        log.setUserAgent(userAgent);
        log.setDetails(details);
        auditLogRepository.save(log);

        if (success) {
            logger.info("Audit: userId={}, action={}, success=true", userId, action);
        } else {
            logger.warn("Audit: userId={}, action={}, success=false, details={}", userId, action, details);
        }
    }

    public boolean isAccountLockedOut(Long userId, String action) {
        LocalDateTime lockoutWindow = LocalDateTime.now().minusMinutes(LOCKOUT_MINUTES);
        long failedAttempts = auditLogRepository.countByUserIdAndActionAndSuccessFalseAndCreatedAtAfter(
                userId, action, lockoutWindow);
        return failedAttempts >= MAX_FAILED_ATTEMPTS;
    }
}

