import com.enterprise.auth.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class MfaService {

    private static final Logger logger = LoggerFactory.getLogger(MfaService.class);
    private static final String ISSUER = "EnterpriseAuth";

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final BackupCodeService backupCodeService;
    private final TotpService totpService;
    private final AuditService auditService;

    public MfaService(UserRepository userRepository, PasswordEncoder passwordEncoder,
                      BackupCodeService backupCodeService, TotpService totpService,
                      AuditService auditService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.backupCodeService = backupCodeService;
        this.totpService = totpService;
        this.auditService = auditService;
    }

    @Transactional
    public AuthResponse registerUser(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            throw new MfaException("Username already exists");
        }
        if (userRepository.existsByEmail(request.getEmail())) {
            throw new MfaException("Email already exists");
        }

        User user = new User();
        user.setUsername(request.getUsername());
        user.setPassword(passwordEncoder.encode(request.getPassword()));
        user.setEmail(request.getEmail());
        user.setMfaEnabled(false);

        userRepository.save(user);

        auditService.logEvent(user.getId(), "REGISTER", true, null, null, "User registered");

        AuthResponse response = new AuthResponse("User registered successfully", true);
        response.setUsername(user.getUsername());
        return response;
    }

    public AuthResponse login(LoginRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (auditService.isAccountLockedOut(user.getId(), "LOGIN")) {
            throw new AccountLockedException("Account is temporarily locked due to too many failed attempts. Please try again later.");
        }

        if (!passwordEncoder.matches(request.getPassword(), user.getPassword())) {
            auditService.logEvent(user.getId(), "LOGIN", false, ipAddress, userAgent, "Invalid password");
            throw new MfaException("Invalid credentials");
        }

        if (user.isMfaEnabled()) {
            auditService.logEvent(user.getId(), "LOGIN", true, ipAddress, userAgent, "Password verified, MFA required");
            AuthResponse response = new AuthResponse("Password verified. MFA verification required.", false);
            response.setMfaRequired(true);
            response.setUsername(user.getUsername());
            return response;
        }

        auditService.logEvent(user.getId(), "LOGIN", true, ipAddress, userAgent, "Login successful (no MFA)");
        AuthResponse response = new AuthResponse("Login successful", true);
        response.setUsername(user.getUsername());
        return response;
    }

    @Transactional
    public MfaSetupResponse initiateMfaSetup(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled for this user");
        }

        String secret = totpService.generateSecret();
        user.setMfaSecret(secret);
        userRepository.save(user);

        String qrCodeUri = totpService.generateQrCodeUri(secret, username, ISSUER);

        MfaSetupResponse response = new MfaSetupResponse();
        response.setSecret(secret);
        response.setQrCodeUri(qrCodeUri);
        response.setMessage("Scan the QR code with your authenticator app, then verify with a TOTP code to complete setup");

        return response;
    }

    @Transactional
    public MfaSetupResponse enableMfa(EnableMfaRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled");
        }

        if (user.getMfaSecret() == null) {
            throw new MfaException("MFA setup has not been initiated. Please call /mfa/setup first.");
        }

        if (!totpService.verifyCode(user.getMfaSecret(), request.getTotpCode())) {
            auditService.logEvent(user.getId(), "MFA_ENABLE", false, ipAddress, userAgent, "Invalid TOTP code during setup");
            throw new MfaException("Invalid TOTP code. Please verify your authenticator app is set up correctly.");
        }

        user.setMfaEnabled(true);
        userRepository.save(user);

        List<String> backupCodes = backupCodeService.generateBackupCodes(user);

        auditService.logEvent(user.getId(), "MFA_ENABLE", true, ipAddress, userAgent, "MFA enabled with backup codes generated");

        MfaSetupResponse response = new MfaSetupResponse();
        response.setSecret(user.getMfaSecret());
        response.setBackupCodes(backupCodes);
        response.setMessage("MFA enabled successfully. IMPORTANT: Save these backup codes in a secure location. They will not be shown again.");

        return response;
    }

    @Transactional
    public AuthResponse verifyMfaCode(MfaVerifyRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        if (auditService.isAccountLockedOut(user.getId(), "MFA_VERIFY")) {
            throw new AccountLockedException("Account is temporarily locked due to too many failed MFA attempts.");
        }

        if (!totpService.verifyCode(user.getMfaSecret(), request.getCode())) {
            auditService.logEvent(user.getId(), "MFA_VERIFY", false, ipAddress, userAgent, "Invalid TOTP code");
            throw new MfaException("Invalid MFA code");
        }

        auditService.logEvent(user.getId(), "MFA_VERIFY", true, ipAddress, userAgent, "MFA verified via TOTP");

        AuthResponse response = new AuthResponse("MFA verification successful. Authentication complete.", true);
        response.setUsername(user.getUsername());
        response.setRemainingBackupCodes(backupCodeService.getRemainingCodesCount(user));
        return response;
    }

    @Transactional
    public AuthResponse verifyBackupCode(BackupCodeVerifyRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        if (auditService.isAccountLockedOut(user.getId(), "BACKUP_CODE_VERIFY")) {
            throw new AccountLockedException("Account is temporarily locked due to too many failed backup code attempts.");
        }

        if (!backupCodeService.verifyBackupCode(user, request.getBackupCode())) {
            auditService.logEvent(user.getId(), "BACKUP_CODE_VERIFY", false, ipAddress, userAgent, "Invalid backup code");
            throw new MfaException("Invalid backup code");
        }

        long remainingCodes = backupCodeService.getRemainingCodesCount(user);
        auditService.logEvent(user.getId(), "BACKUP_CODE_VERIFY", true, ipAddress, userAgent,
                "Backup code verified. Remaining: " + remainingCodes);

        AuthResponse response = new AuthResponse();
        response.setAuthenticated(true);
        response.setUsername(user.getUsername());
        response.setRemainingBackupCodes(remainingCodes);

        if (remainingCodes == 0) {
            response.setMessage("Authentication successful. WARNING: You have no remaining backup codes! Please regenerate backup codes immediately.");
        } else if (remainingCodes <= 2) {
            response.setMessage("Authentication successful. WARNING: You only have " + remainingCodes + " backup codes remaining. Consider regenerating them.");
        } else {
            response.setMessage("Authentication successful via backup code. Remaining backup codes: " + remainingCodes);
        }

        return response;
    }

    @Transactional
    public MfaSetupResponse regenerateBackupCodes(String username, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        List<String> newCodes = backupCodeService.regenerateBackupCodes(user);

        auditService.logEvent(user.getId(), "BACKUP_CODES_REGENERATED", true, ipAddress, userAgent,
                "Backup codes regenerated. Old codes invalidated.");

        MfaSetupResponse response = new MfaSetupResponse();
        response.setBackupCodes(newCodes);
        response.setMessage("New backup codes generated. All previous backup codes have been invalidated. Save these codes securely.");

        return response;
    }

    public BackupCodeStatusResponse getBackupCodeStatus(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        long remaining = backupCodeService.getRemainingCodesCount(user);
        long total = user.getBackupCodes().size();
        long used = total - remaining;

        BackupCodeStatusResponse response = new BackupCodeStatusResponse();
        response.setTotalCodes(total);
        response.setUsedCodes(used);
        response.setRemainingCodes(remaining);

        if (remaining == 0) {
            response.setMessage("CRITICAL: No backup codes remaining. Regenerate immediately!");
        } else if (remaining <= 2) {
            response.setMessage("WARNING: Low backup codes. Consider regenerating.");
        } else {
            response.setMessage("Backup codes status OK.");
        }

        return response;
    }

    @Transactional
    public AuthResponse disableMfa(String username, String totpCode, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        if (!totpService.verifyCode(user.getMfaSecret(), totpCode)) {
            auditService.logEvent(user.getId(), "MFA_DISABLE", false, ipAddress, userAgent, "Invalid TOTP code");
            throw new MfaException("Invalid TOTP code. Cannot disable MFA.");
        }

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        user.getBackupCodes().clear();
        userRepository.save(user);

        auditService.logEvent(user.getId(), "MFA_DISABLE", true, ipAddress, userAgent, "MFA disabled");

        return new AuthResponse("MFA has been disabled successfully.", true);
    }
}

// === Controller: AuthController ===

package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.MfaService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final MfaService mfaService;

    public AuthController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/register")
    public ResponseEntity<AuthResponse> register(@Valid @RequestBody RegisterRequest request) {
        AuthResponse response = mfaService.registerUser(request);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/login")
    public ResponseEntity<AuthResponse> login(@Valid @RequestBody LoginRequest request, HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        AuthResponse response = mfaService.login(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/mfa/verify")
    public ResponseEntity<AuthResponse> verifyMfa(@Valid @RequestBody MfaVerifyRequest request, HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        AuthResponse response = mfaService.verifyMfaCode(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/mfa/backup-code/verify")
    public ResponseEntity<AuthResponse> verifyBackupCode(@Valid @RequestBody BackupCodeVerifyRequest request, HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        AuthResponse response = mfaService.verifyBackupCode(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

// === Controller: MfaManagementController ===

package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.MfaService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
public class MfaManagementController {

    private final MfaService mfaService;

    public MfaManagementController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/setup/{username}")
    public ResponseEntity<MfaSetupResponse> initiateMfaSetup(@PathVariable String username) {
        MfaSetupResponse response = mfaService.initiateMfaSetup(username);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/enable")
    public ResponseEntity<MfaSetupResponse> enableMfa(@Valid @RequestBody EnableMfaRequest request, HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        MfaSetupResponse response = mfaService.enableMfa(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/disable/{username}")
    public ResponseEntity<AuthResponse> disableMfa(@PathVariable String username,
                                                    @RequestParam String totpCode,
                                                    HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        AuthResponse response = mfaService.disableMfa(username, totpCode, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/backup-codes/regenerate/{username}")
    public ResponseEntity<MfaSetupResponse> regenerateBackupCodes(@PathVariable String username, HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        MfaSetupResponse response = mfaService.regenerateBackupCodes(username, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/backup-codes/status/{username}")
    public ResponseEntity<BackupCodeStatusResponse> getBackupCodeStatus(@PathVariable String username) {
        BackupCodeStatusResponse response = mfaService.getBackupCodeStatus(username);
        return ResponseEntity.ok(response);
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

// === Security Configuration ===

package com.enterprise.auth.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.annotation.web.configurers.HeadersConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder(12);
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(AbstractHttpConfigurer::disable)
                .headers(headers -> headers.frameOptions(HeadersConfigurer.FrameOptionsConfig::sameOrigin))
                .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/auth/**").permitAll()
                        .requestMatchers("/api/mfa/**").permitAll()
                        .requestMatchers("/h2-console/**").permitAll()
                        .anyRequest().authenticated()
                );

        return http.build();
    }
}

